      if (!duration.durationMinutes) continue;

      const hour = duration.startTime.getHours();
      const stats = hourStats.get(hour) || { count: 0, durations: [] };
      stats.count++;
      stats.durations.push(duration.durationMinutes);
      hourStats.set(hour, stats);
